// For loop — when you know how many times
for (let i = 0; i < 5; i++) {
  console.log('Iteration ' + i);
}

// For...of — when looping through a list
let fruits = ['apple', 'banana', 'cherry'];
for (let fruit of fruits) {
  console.log(fruit);
}

// While loop — when you don't know when to stop
let count = 0;
while (count < 3) {
  console.log(count);
  count++;
}

